it('formats price with currency symbol', () => {
  // Arrange
  const price = 1234.56;

  // Act
  const result = formatPrice(price, 'USD');

  // Assert
  expect(result).toBe('$1,234.56');
});

it('loads user profile on mount', async () => {
  vi.mocked(fetchUser).mockResolvedValue({ id: 1, name: 'Alice' });

  render(<UserProfile userId={1} />);

  // findBy* waits automatically — no manual waitFor needed
  const name = await screen.findByText('Alice');
  expect(name).toBeInTheDocument();
});

describe('debounced search', () => {
  beforeEach(() => vi.useFakeTimers());
  afterEach(() => vi.useRealTimers());

  it('delays the search call by 300ms', () => {
    const onSearch = vi.fn();
    render(<SearchInput onSearch={onSearch} debounceMs={300} />);

    fireEvent.change(screen.getByRole('textbox'), { target: { value: 'test' } });
    expect(onSearch).not.toHaveBeenCalled();

    vi.advanceTimersByTime(300);
    expect(onSearch).toHaveBeenCalledWith('test');
  });
});

